class Solution {
public:
    int maxValue(int n, int index, int maxSum) {
        int left = 1, right = maxSum;
        while (left < right) {
            int mid = left + (right - left) / 2;
            int sum = 0, prev = 0;
            for (int i = 0; i < n; i++) {
                sum += mid;
                if (i < index) {
                    prev = mid;
                } else {
                    prev = prev + 1;
                }
                if (sum > maxSum) break;
            }
            if (sum > maxSum) right = mid;
            else left = mid + 1;
        }
        return left - 1;
    }
};
